#include <bits/stdc++.h>
using namespace std;

int arrangeHouses(int n) {
    long long house = 1, space = 1;
    long long total = house + space;
    long long mod = 1000000007;

    // For each position after 1
    for(int i = 2; i <= n; i++) {
        house = space;                    // New house can be placed where there was space
        space = total;                    // New space can be placed after any previous arrangement
        total = (house + space) % mod;    // Total arrangements for this position
    }

    return (total * total) % mod;         // Square because same arrangement can be done on both sides
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;
        cout << arrangeHouses(n) << endl;
    }
    return 0;
}
